prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?taskName ?task WHERE {
  ?model a bboExt:Model ;
         tai:normalizedId "5a8e825c3a9a4049b67ab53c2ba7abc8" .
  ?defs tai:belongsTo ?model .
  ?choreo tai:belongsTo ?defs .

  # Initial/start nodes (start events)
  ?start a bboExt:StartEvent ;
         tai:belongsTo ?choreo .

  # All tasks reachable from ANY start node
  {
    ?start ((^bbo:has_sourceRef)/bbo:has_targetRef)+ ?reachNode .
    ?reachNode a bboExt:ChoreographyTask ;
                tai:belongsTo ?choreo .
  }
  BIND(?reachNode AS ?reachableTask)

  # Candidate tasks
  ?task a bboExt:ChoreographyTask ;
        bbo:name ?taskName ;
        tai:belongsTo ?choreo .

  FILTER NOT EXISTS {
    ?start2 ((^bbo:has_sourceRef)/bbo:has_targetRef)+ ?reachableTask2 .
    ?reachableTask2 a bboExt:ChoreographyTask ;
                     tai:belongsTo ?choreo .
    FILTER(?reachableTask2 = ?task)
    # keep link to model
    ?start2 a bboExt:StartEvent ; tai:belongsTo ?choreo .
  }
}
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?startType ?startName ?start WHERE {
  ?model a bboExt:Model ;
         tai:normalizedId "5a8e825c3a9a4049b67ab53c2ba7abc8" .
  ?defs tai:belongsTo ?model .
  ?choreo tai:belongsTo ?defs .

  ?start a ?startType ;
         tai:belongsTo ?choreo .
  OPTIONAL { ?start bbo:name ?startName . }

  FILTER(
    ?startType = bboExt:StartEvent ||
    ?startType = bboExt:IntermediateCatchEvent ||
    ?startType = bboExt:EventBasedGateway
  )
}
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?model ?idType ?idValue ?modelName WHERE {
  ?model a bboExt:Model .
  OPTIONAL { ?model bbo:name ?modelName . }

  {
    ?model tai:normalizedId ?idValue .
    BIND("normalizedId" AS ?idType)
    FILTER(?idValue = "5a8e825c3a9a4049b67ab53c2ba7abc8")
  }
  UNION
  {
    ?model tai:originalId ?idValue .
    BIND("originalId" AS ?idType)
    FILTER(?idValue = "5a8e825c3a9a4049b67ab53c2ba7abc8")
  }
  UNION
  {
    ?model tai:corpusId ?idValue .
    BIND("corpusId" AS ?idType)
    FILTER(?idValue = "5a8e825c3a9a4049b67ab53c2ba7abc8")
  }
}
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?taskName ?task WHERE {
  # Model
  ?model a bboExt:Model ;
         tai:originalId "5a8e825c3a9a4049b67ab53c2ba7abc8" .
  ?defs tai:belongsTo ?model .

  # Find choreography container
  ?choreo tai:belongsTo ?defs .
  ?choreo a bboExt:Choreography .

  # All tasks in choreography
  ?task a bboExt:ChoreographyTask ;
        tai:belongsTo ?choreo .
  OPTIONAL { ?task bbo:name ?taskName . }

  # Initial nodes: start events
  ?start a bboExt:StartEvent ;
          tai:belongsTo ?choreo .

  # Keep tasks that are NOT reachable from any start
  FILTER NOT EXISTS {
    ?start2 a bboExt:StartEvent ;
            tai:belongsTo ?choreo .

    ?start2 ((^bbo:has_sourceRef)/bbo:has_targetRef)+ ?reachableTask .
    ?reachableTask a bboExt:ChoreographyTask ;
                    tai:belongsTo ?choreo .

    FILTER(?reachableTask = ?task)
  }
}
LIMIT 25
